const run = $('Seed Dispatcher Run').item.json;
const rows = $input.all().map((i) => i.json).filter((row) => row && row.id);
return rows.map((task) => ({ json: { run, task } }));

const run = $json.run;
const task = $json.task;
return [{
  json: {
    run,
    task,
    task_id: task.id,
    org_id: task.org_id,
    conversation_id: task.conversation_id,
    contact_id: task.contact_id,
    platform: task.platform,
    due_at: task.due_at,
    latest_inbound_at: task.latest_inbound_at ?? null,
    triggered_by_message_id: task.triggered_by_message_id ?? null,
    requires_template: Boolean(task.requires_template ?? false),
    template_name: task.template_name ?? null,
    template_language: task.template_language ?? null,
    template_status: task.template_status ?? null,
    org_channel_account_id: task.org_channel_account_id ?? null,
    now_iso: run.now_iso,
    claimed_at_iso: new Date().toISOString()
  }
}];

const normalized = $('Normalize Task Context').item.json;
const updatedRows = $input.all().map((i) => i.json).filter((row) => row && row.id);
return [{
  json: {
    ...normalized,
    claim_acquired: updatedRows.length > 0,
    claimed_row: updatedRows[0] ?? null
  }
}];

return [{
  json: {
    org_id: $json.org_id,
    task_id: $json.task_id,
    conversation_id: $json.conversation_id,
    contact_id: $json.contact_id ?? null,
    event_type: 'claimed',
    details: {
      run_id: $json.run.run_id,
      claimed_at: $json.claimed_at_iso,
      platform: $json.platform
    },
    created_at: new Date().toISOString()
  }
}];

function parseJson(value, fallback) {
  if (value === null || value === undefined || value === '') return fallback;
  if (typeof value === 'object') return value;
  try {
    return JSON.parse(value);
  } catch {
    return fallback;
  }
}
function firstReal(nodeName) {
  const all = $(nodeName).all().map((i) => i.json).filter((row) => row && Object.keys(row).length > 0);
  return all.length ? all[0] : null;
}
function allRows(nodeName) {
  return $(nodeName).all().map((i) => i.json).filter((row) => row && Object.keys(row).length > 0);
}
function getTimeZoneOffset(date, timeZone) {
  const dtf = new Intl.DateTimeFormat('en-US', {
    timeZone,
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
    hour: '2-digit',
    minute: '2-digit',
    second: '2-digit',
    hour12: false
  });
  const parts = dtf.formatToParts(date);
  const map = {};
  for (const part of parts) {
    if (part.type !== 'literal') map[part.type] = part.value;
  }
  const asUTC = Date.UTC(
    Number(map.year),
    Number(map.month) - 1,
    Number(map.day),
    Number(map.hour),
    Number(map.minute),
    Number(map.second)
  );
  return asUTC - date.getTime();
}
function zonedTimeToUtc(timeZone, year, month, day, hour, minute, second = 0) {
  const guess = new Date(Date.UTC(year, month - 1, day, hour, minute, second));
  const offset = getTimeZoneOffset(guess, timeZone);
  return new Date(guess.getTime() - offset);
}
function localParts(date, timeZone) {
  const dtf = new Intl.DateTimeFormat('en-GB', {
    timeZone,
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
    weekday: 'short',
    hour: '2-digit',
    minute: '2-digit',
    second: '2-digit',
    hour12: false
  });
  const parts = dtf.formatToParts(date);
  const map = {};
  for (const part of parts) {
    if (part.type !== 'literal') map[part.type] = part.value;
  }
  const weekdayMap = { Mon: 1, Tue: 2, Wed: 3, Thu: 4, Fri: 5, Sat: 6, Sun: 7 };
  return {
    year: Number(map.year),
    month: Number(map.month),
    day: Number(map.day),
    hour: Number(map.hour),
    minute: Number(map.minute),
    second: Number(map.second),
    weekday: weekdayMap[map.weekday] || 1
  };
}
function normalizeStatus(v) {
  return String(v || '').trim().toLowerCase();
}
function approvedTemplateStatus(v) {
  const s = normalizeStatus(v);
  return ['approved', 'active', 'enabled', 'quality_pending', 'pending_quality_check'].includes(s);
}
function pendingTemplateStatus(v) {
  const s = normalizeStatus(v);
  return ['pending', 'submitted', 'in_review', 'pending_review'].includes(s);
}
function rejectedTemplateStatus(v) {
  const s = normalizeStatus(v);
  return ['rejected', 'disabled', 'paused'].includes(s);
}
function pickSenderAccount(contextTaskAccountId, accounts) {
  if (contextTaskAccountId) {
    const exact = accounts.find((a) => a.id === contextTaskAccountId && a.is_active === true);
    if (exact) return exact;
  }
  return accounts.find((a) => a.is_active === true) || null;
}
function pickPhoneNumber(account, rows) {
  if (!account) return null;
  const candidates = rows.filter((row) => row.org_channel_account_id === account.id && (row.is_active === undefined || row.is_active === true || String(row.status || '').toUpperCase() === 'CONNECTED'));
  if (!candidates.length) return null;
  const defaultRow = candidates.find((row) => row.is_default === true);
  return defaultRow || candidates[0];
}
function chooseLanguage(contact, task) {
  const meta = parseJson(contact?.meta, {});
  const raw = String(meta.language || meta.lang || task.resolved_language || '').trim().toLowerCase();
  if (raw.startsWith('ar')) return 'ar';
  return 'en';
}
function interpolateMessage(template, contact) {
  const name = String(contact?.display_name || contact?.username || contact?.phone || 'there');
  return String(template || '').replace(/\{name\}/g, name);
}

const taskContext = $('Interpret Claim Result').item.json;
const task = taskContext.task || {};
const conversation = firstReal('Load Conversation');
const contact = firstReal('Load Contact');
const latestInboundMessage = firstReal('Load Latest Inbound Message');
const settings = firstReal('Load Followup Settings') || {};
const organization = firstReal('Load Organization') || {};
const senderAccounts = allRows('Load Org Channel Accounts');
const phoneRows = allRows('Load WhatsApp Phone Numbers');
const templateRows = allRows('Load WhatsApp Templates');
const submissionRows = allRows('Load Template Submissions');

const now = new Date(taskContext.now_iso || new Date().toISOString());
const orgSettings = parseJson(organization.settings, {});
const timeZone = String(orgSettings.timezone || 'UTC');

const base = {
  run: taskContext.run,
  task,
  task_id: taskContext.task_id,
  org_id: taskContext.org_id,
  conversation_id: taskContext.conversation_id,
  contact_id: taskContext.contact_id,
  platform: taskContext.platform,
  due_at: taskContext.due_at,
  latest_inbound_at: taskContext.latest_inbound_at,
  triggered_by_message_id: taskContext.triggered_by_message_id,
  requires_template: Boolean(taskContext.requires_template ?? false),
  template_name: taskContext.template_name,
  template_language: taskContext.template_language,
  template_status: taskContext.template_status,
  org_channel_account_id: taskContext.org_channel_account_id,
  now_iso: now.toISOString(),
  time_zone: timeZone
};

const result = {
  ...base,
  action: null,
  terminal_type: null,
  error_code: null,
  error_message: null,
  blocked_reason: null,
  waiting_for_template_approval: false,
  next_business_due_at: null,
  resolved_message: null,
  resolved_language: null,
  sender: null,
  whatsapp_phone: null,
  template_name_to_send: taskContext.template_name || null,
  template_language_to_send: taskContext.template_language || null,
  template_status_known: normalizeStatus(taskContext.template_status || ''),
  template_required_now: false,
  template_approved_now: false,
  business_hours_deferred: false,
  log_events: [],
  should_notify: false,
  notification: null,
  notification_state: parseJson(task.notification_state, {}),
  recipient_address: null,
  send_mode: null,
  whatsapp_template_request_body: null,
  whatsapp_freeform_request_body: null
};

if (!conversation) {
  result.terminal_type = 'cancelled';
  result.error_code = 'conversation_not_found';
  result.error_message = 'Conversation not found.';
  result.log_events.push({ event_type: 'cancelled', details: { reason: 'conversation_not_found' } });
  return [{ json: result }];
}

if (String(conversation.status || '').toLowerCase() === 'closed') {
  result.terminal_type = 'cancelled';
  result.error_code = 'conversation_closed';
  result.error_message = 'Conversation is closed.';
  result.log_events.push({ event_type: 'cancelled', details: { reason: 'conversation_closed' } });
  return [{ json: result }];
}

if (conversation.ai_paused === true) {
  result.terminal_type = 'cancelled';
  result.error_code = 'ai_paused';
  result.error_message = 'Conversation AI is paused.';
  result.log_events.push({ event_type: 'cancelled', details: { reason: 'ai_paused' } });
  return [{ json: result }];
}

const newestInboundAt = latestInboundMessage?.created_at || conversation.last_inbound_at || taskContext.latest_inbound_at || null;
if (newestInboundAt && taskContext.latest_inbound_at && new Date(newestInboundAt).getTime() > new Date(taskContext.latest_inbound_at).getTime()) {
  result.terminal_type = 'cancelled';
  result.error_code = 'newer_inbound_reply';
  result.error_message = 'A newer inbound customer message invalidated this follow-up.';
  result.log_events.push({ event_type: 'cancelled', details: { reason: 'newer_inbound_reply', latest_inbound_at: newestInboundAt } });
  return [{ json: result }];
}

const sender = pickSenderAccount(taskContext.org_channel_account_id, senderAccounts);
result.sender = sender;
if (result.platform === 'whatsapp') {
  result.whatsapp_phone = pickPhoneNumber(sender, phoneRows);
}
if (!sender) {
  result.terminal_type = 'failed';
  result.error_code = 'sender_not_found';
  result.error_message = 'No active sender account found for platform.';
  result.log_events.push({ event_type: 'failed', details: { reason: 'sender_not_found', platform: result.platform } });
  return [{ json: result }];
}
if (result.platform === 'whatsapp' && !result.whatsapp_phone) {
  result.terminal_type = 'failed';
  result.error_code = 'whatsapp_phone_not_found';
  result.error_message = 'No usable WhatsApp phone number found for sender.';
  result.log_events.push({ event_type: 'failed', details: { reason: 'whatsapp_phone_not_found', sender_account_id: sender.id } });
  return [{ json: result }];
}

const resolvedLanguage = chooseLanguage(contact, task);
const byChannel = parseJson(settings.followup_message_by_channel, {});
const byChannelAr = parseJson(settings.followup_message_ar_by_channel, {});
let messageTemplate = null;
if (resolvedLanguage === 'ar') {
  messageTemplate = byChannelAr?.[result.platform] || settings.followup_message_ar || byChannel?.[result.platform] || settings.followup_message || '';
} else {
  messageTemplate = byChannel?.[result.platform] || settings.followup_message || byChannelAr?.[result.platform] || settings.followup_message_ar || '';
}
result.resolved_message = interpolateMessage(messageTemplate, contact);
result.resolved_language = resolvedLanguage;
result.recipient_address = contact?.phone || contact?.external_contact_id || null;

if (!result.resolved_message && result.platform !== 'whatsapp') {
  result.terminal_type = 'failed';
  result.error_code = 'followup_message_missing';
  result.error_message = 'No follow-up message configured.';
  result.log_events.push({ event_type: 'failed', details: { reason: 'followup_message_missing' } });
  return [{ json: result }];
}

if (settings.business_hours_enabled === true) {
  const businessStart = String(settings.business_start || '09:00:00').slice(0,5);
  const businessEnd = String(settings.business_end || '18:00:00').slice(0,5);
  const [startHour, startMinute] = businessStart.split(':').map(Number);
  const [endHour, endMinute] = businessEnd.split(':').map(Number);
  const lp = localParts(now, timeZone);
  const currentMinutes = lp.hour * 60 + lp.minute;
  const startMinutes = startHour * 60 + startMinute;
  const endMinutes = endHour * 60 + endMinute;
  const inside = currentMinutes >= startMinutes && currentMinutes < endMinutes;
  if (!inside) {
    let y = lp.year, m = lp.month, d = lp.day;
    const tomorrow = new Date(Date.UTC(lp.year, lp.month - 1, lp.day));
    if (currentMinutes >= endMinutes) {
      tomorrow.setUTCDate(tomorrow.getUTCDate() + 1);
      const tparts = localParts(tomorrow, timeZone);
      y = tparts.year; m = tparts.month; d = tparts.day;
    }
    const due = zonedTimeToUtc(timeZone, y, m, d, startHour, startMinute, 0);
    result.terminal_type = 'deferred';
    result.business_hours_deferred = true;
    result.next_business_due_at = due.toISOString();
    result.log_events.push({ event_type: 'deferred_business_hours', details: { previous_due_at: result.due_at, next_due_at: result.next_business_due_at, timezone: timeZone } });
    return [{ json: result }];
  }
}

if (result.platform === 'whatsapp') {
  const latestInboundDate = newestInboundAt ? new Date(newestInboundAt) : null;
  const hoursSinceLatestInbound = latestInboundDate ? (now.getTime() - latestInboundDate.getTime()) / 3600000 : null;
  const policyEnabled = settings.whatsapp_template_required_after_24h === true;
  const beyond24h = latestInboundDate ? hoursSinceLatestInbound > 24 : true;
  const taskTemplateName = taskContext.template_name || settings.whatsapp_template_name || null;
  const taskTemplateLanguage = taskContext.template_language || settings.whatsapp_template_language || null;
  result.template_name_to_send = taskTemplateName;
  result.template_language_to_send = taskTemplateLanguage;

  let matchedTemplate = null;
  if (taskTemplateName && taskTemplateLanguage) {
    matchedTemplate = templateRows.find((row) =>
      String(row.name || '').trim().toLowerCase() === String(taskTemplateName).trim().toLowerCase() &&
      String(row.language || '').trim().toLowerCase() === String(taskTemplateLanguage).trim().toLowerCase() &&
      (!row.org_channel_account_id || row.org_channel_account_id === sender.id || row.org_id === result.org_id)
    ) || null;
  }
  let submission = null;
  if (taskTemplateName && taskTemplateLanguage) {
    submission = submissionRows.find((row) =>
      String(row.template_name || row.name || '').trim().toLowerCase() === String(taskTemplateName).trim().toLowerCase() &&
      String(row.language || row.template_language || '').trim().toLowerCase() === String(taskTemplateLanguage).trim().toLowerCase()
    ) || null;
  }

  const knownStatus = normalizeStatus(matchedTemplate?.status || submission?.status || taskContext.template_status || settings.whatsapp_template_status || '');
  result.template_status_known = knownStatus;

  if (policyEnabled && beyond24h) {
    result.template_required_now = true;
    result.log_events.push({ event_type: 'template_required', details: { latest_inbound_at: newestInboundAt, hours_since_latest_inbound: hoursSinceLatestInbound, template_name: taskTemplateName, template_language: taskTemplateLanguage } });
    if (matchedTemplate && approvedTemplateStatus(matchedTemplate.status)) {
      result.template_approved_now = task.status === 'waiting_template_approval';
      if (result.template_approved_now) {
        result.log_events.push({ event_type: 'template_approved', details: { template_name: taskTemplateName, template_language: taskTemplateLanguage, status: matchedTemplate.status } });
      }
      if (result.template_approved_now && settings.notification_on_template_approved === true) {
        result.should_notify = true;
        result.notification = {
          type: 'followup_template',
          title: 'WhatsApp template approved',
          message: 'A WhatsApp follow-up template is now approved and the follow-up is resuming.',
          event_key: 'template_approved',
          payload: {
            task_id: result.task_id,
            conversation_id: result.conversation_id,
            platform: result.platform,
            template_name: taskTemplateName,
            template_language: taskTemplateLanguage,
            status: matchedTemplate.status,
            entity: 'followup',
            entity_id: result.task_id
          }
        };
        result.notification_state = {
          ...(result.notification_state || {}),
          template_approved: now.toISOString()
        };
      }
      result.action = 'send_template';
      result.send_mode = 'whatsapp_template';
      result.whatsapp_template_request_body = {
        messaging_product: 'whatsapp',
        recipient_type: 'individual',
        to: result.recipient_address,
        type: 'template',
        template: {
          name: taskTemplateName,
          language: { code: taskTemplateLanguage }
        }
      };
      return [{ json: result }];
    }

    result.terminal_type = 'waiting_template_approval';
    result.waiting_for_template_approval = true;
    result.blocked_reason = 'template_missing_or_not_approved';

    if (submission) {
      if (rejectedTemplateStatus(submission.status)) {
        result.log_events.push({ event_type: 'template_rejected', details: { template_name: taskTemplateName, template_language: taskTemplateLanguage, status: submission.status } });
      } else if (pendingTemplateStatus(submission.status) || !submission.status) {
        result.log_events.push({ event_type: 'template_submission_pending', details: { template_name: taskTemplateName, template_language: taskTemplateLanguage, status: submission.status || 'pending' } });
      }
    } else {
      result.log_events.push({ event_type: 'template_submission_requested', details: { template_name: taskTemplateName, template_language: taskTemplateLanguage } });
    }
    result.log_events.push({ event_type: 'waiting_template_approval', details: { template_name: taskTemplateName, template_language: taskTemplateLanguage, current_status: knownStatus || null } });

    const notifySubmitted = settings.notification_on_template_submitted === true && !submission;
    const notifyApproved = settings.notification_on_template_approved === true && result.template_approved_now;
    const notifyRejected = settings.notification_on_template_rejected === true && submission && rejectedTemplateStatus(submission.status);
    if (notifySubmitted || notifyApproved || notifyRejected) {
      let kind = 'template_submission_requested';
      let title = 'WhatsApp template required';
      let message = 'A follow-up is waiting for an approved WhatsApp template.';
      if (notifyApproved) {
        kind = 'template_approved';
        title = 'WhatsApp template approved';
        message = 'A WhatsApp follow-up template is now approved and the follow-up can resume.';
      } else if (notifyRejected) {
        kind = 'template_rejected';
        title = 'WhatsApp template rejected';
        message = 'A WhatsApp follow-up template was rejected and follow-up remains blocked.';
      }
      result.should_notify = true;
      result.notification = {
        type: 'followup_template',
        title,
        message,
        event_key: kind,
        payload: {
          task_id: result.task_id,
          conversation_id: result.conversation_id,
          platform: result.platform,
          template_name: taskTemplateName,
          template_language: taskTemplateLanguage,
          status: submission?.status || knownStatus || null,
          entity: 'followup',
          entity_id: result.task_id
        }
      };
      result.notification_state = {
        ...(result.notification_state || {}),
        [kind]: now.toISOString()
      };
    }
    return [{ json: result }];
  }

  result.action = 'send_freeform';
  result.send_mode = 'whatsapp_freeform';
  result.whatsapp_freeform_request_body = {
    messaging_product: 'whatsapp',
    recipient_type: 'individual',
    to: result.recipient_address,
    type: 'text',
    text: {
      body: result.resolved_message,
      preview_url: false
    }
  };
  return [{ json: result }];
}

if (result.platform === 'page' || result.platform === 'instagram') {
  result.terminal_type = 'failed';
  result.error_code = 'provider_send_not_implemented';
  result.error_message = 'Provider sending is not implemented for this platform in this workflow.';
  result.log_events.push({ event_type: 'failed', details: { reason: 'provider_send_not_implemented', platform: result.platform } });
  return [{ json: result }];
}

result.terminal_type = 'failed';
result.error_code = 'unsupported_platform';
result.error_message = 'Unsupported follow-up platform.';
result.log_events.push({ event_type: 'failed', details: { reason: 'unsupported_platform', platform: result.platform } });
return [{ json: result }];

const ctx = $('Build Dispatch Context').item.json;
const now = new Date().toISOString();
let taskUpdate = { updated_at: now };
if (ctx.terminal_type === 'cancelled') {
  taskUpdate.status = 'cancelled';
  taskUpdate.cancelled_at = now;
  taskUpdate.error_message = ctx.error_message || null;
  taskUpdate.blocked_reason = ctx.blocked_reason || null;
} else if (ctx.terminal_type === 'skipped') {
  taskUpdate.status = 'skipped';
  taskUpdate.error_message = ctx.error_message || null;
  taskUpdate.blocked_reason = ctx.blocked_reason || null;
} else if (ctx.terminal_type === 'failed') {
  taskUpdate.status = 'failed';
  taskUpdate.failed_at = now;
  taskUpdate.resolved_message = ctx.resolved_message || null;
  taskUpdate.resolved_language = ctx.resolved_language || null;
  taskUpdate.error_message = ctx.error_message || null;
  taskUpdate.blocked_reason = ctx.blocked_reason || null;
} else if (ctx.terminal_type === 'deferred') {
  taskUpdate.status = 'scheduled';
  taskUpdate.due_at = ctx.next_business_due_at;
} else if (ctx.terminal_type === 'waiting_template_approval') {
  taskUpdate.status = 'waiting_template_approval';
  taskUpdate.waiting_for_template_approval = true;
  taskUpdate.blocked_reason = ctx.blocked_reason || 'template_missing_or_not_approved';
  taskUpdate.template_name = ctx.template_name_to_send || ctx.template_name || null;
  taskUpdate.template_language = ctx.template_language_to_send || ctx.template_language || null;
  taskUpdate.template_status = ctx.template_status_known || null;
  taskUpdate.error_message = null;
  taskUpdate.notification_state = ctx.notification_state || null;
}
return [{
  json: {
    task_id: ctx.task_id,
    org_id: ctx.org_id,
    conversation_id: ctx.conversation_id,
    contact_id: ctx.contact_id,
    task_update: taskUpdate,
    log_events: ctx.log_events || [],
    should_notify: Boolean(ctx.should_notify),
    notification: ctx.notification || null
  }
}];

const input = $input.all()[0].json;
const now = new Date().toISOString();
const rows = (input.log_events || []).map((event) => ({
  org_id: input.org_id,
  task_id: input.task_id,
  conversation_id: input.conversation_id,
  contact_id: input.contact_id || null,
  event_type: event.event_type,
  details: event.details || {},
  created_at: now
}));
return rows.map((row) => ({ json: row }));

const ctx = $('Build Dispatch Context').item.json;
const raw = $input.all()[0].json || {};
const statusCode = raw.statusCode ?? 200;
const body = raw.body ?? raw;
let providerMessageId = null;
if (Array.isArray(body.messages) && body.messages.length) {
  providerMessageId = body.messages[0].id || null;
}
const sendSuccess = statusCode >= 200 && statusCode < 300 && !body.error && !!providerMessageId;
return [{
  json: {
    ...ctx,
    provider_response: body,
    provider_status_code: statusCode,
    provider_message_id: providerMessageId,
    send_success: sendSuccess,
    send_error_message: sendSuccess ? null : JSON.stringify(body.error || body)
  }
}];

const ctx = $('Interpret Provider Response').item.json;
const now = new Date().toISOString();
const taskUpdate = {
  status: 'sent',
  sent_at: now,
  resolved_message: ctx.resolved_message || null,
  resolved_language: ctx.resolved_language || null,
  provider_message_id: ctx.provider_message_id || null,
  provider_response: ctx.provider_response || null,
  org_channel_account_id: ctx.sender?.id || null,
  waiting_for_template_approval: false,
  blocked_reason: null,
  template_status: ctx.template_status_known || null,
  notification_state: ctx.notification_state || null,
  updated_at: now
};
const logEvents = [...(ctx.log_events || [])];
logEvents.push({ event_type: 'sent', details: { provider_message_id: ctx.provider_message_id || null, send_mode: ctx.send_mode, org_channel_account_id: ctx.sender?.id || null } });
return [{
  json: {
    task_id: ctx.task_id,
    org_id: ctx.org_id,
    conversation_id: ctx.conversation_id,
    contact_id: ctx.contact_id,
    task_update: taskUpdate,
    log_events: logEvents,
    should_notify: Boolean(ctx.should_notify),
    notification: ctx.notification || null
  }
